export const LAND_AREAS: readonly BoardAreaGeometry[] = Object.freeze([
    ...LEFTMOST_ISLAND_AREAS,
    ...SOUTHLEFT_ISLAND_AREAS,
    ...TOP_CENTER_ISLAND_AREAS,
    ...EASTCENTRAL_ISLAND_AREAS,
    ...SOUTHCHAIN_ISLAND_AREAS,
    ...NORTHEAST_ISLAND_AREAS,
    ...EAST_ISLAND_AREAS
])

export const ALL_BOARD_AREAS: readonly BoardAreaGeometry[] = Object.freeze([
    ...LAND_AREAS,
    ...SEA_AREAS
])

export const BOARD_AREA_PATH_BY_ID: ReadonlyMap<string, string> = new Map(
    ALL_BOARD_AREAS.map((area) => [area.id, area.path] as const)
)

export function boardAreaPathById(areaId: string): string | undefined {
    return BOARD_AREA_PATH_BY_ID.get(areaId)
}
